import type { Type } from "arktype"
import { jsonSchemaToType } from "@ark/json-schema"

const DRAFT_2020_12_URI = "https://json-schema.org/draft/2020-12/schema"

/**
 * Export an ArkType Type to a JSON Schema document (draft-2020-12).
 * The returned object includes the `$schema` field.
 */
export function exportJsonSchema(schema: Type): object {
  return schema.toJsonSchema({ dialect: DRAFT_2020_12_URI })
}

/**
 * Round-trip an ArkType Type through JSON Schema:
 *   1. Convert to JSON Schema via toJsonSchema()
 *   2. Parse back into an ArkType Type via @ark/json-schema
 *   3. Return the re-parsed Type
 */
export function roundTrip(schema: Type): Type {
  const jsonSchema = exportJsonSchema(schema)
  return jsonSchemaToType(jsonSchema)
}

import { type as typeParser } from "arktype"
import { ArkErrors } from "arktype"
import { exportJsonSchema, roundTrip } from "./roundTrip.ts"

function readStdin(): Promise<string> {
  return new Promise((resolve, reject) => {
    let data = ""
    process.stdin.setEncoding("utf8")
    process.stdin.on("data", (chunk: string) => {
      data += chunk
    })
    process.stdin.on("end", () => resolve(data))
    process.stdin.on("error", reject)
  })
}

async function main(): Promise<void> {
  const stdin = await readStdin()
  const input = JSON.parse(stdin)
  const { schema: schemaDef, corpus } = input

  // Build original type from the ArkType definition
  const originalType = typeParser(schemaDef)

  // Round-trip through JSON Schema
  const roundTrippedType = roundTrip(originalType)
  const jsonSchema = exportJsonSchema(originalType)

  // Check each payload in the corpus
  const agreements = corpus.map((payload: unknown, index: number) => {
    const originalResult = originalType(payload)
    const roundTrippedResult = roundTrippedType(payload)
    const originalAccept = !(originalResult instanceof ArkErrors)
    const roundTrippedAccept = !(roundTrippedResult instanceof ArkErrors)
    return {
      index,
      originalAccept,
      roundTrippedAccept,
      agree: originalAccept === roundTrippedAccept
    }
  })

  const allAgree = agreements.every((a: { agree: boolean }) => a.agree)

  const result = {
    jsonSchema,
    agreements,
    allAgree
  }

  console.log(JSON.stringify(result))
  process.exit(allAgree ? 0 : 0)
}

main()

